const email = $input.first().json;

// Filtra apenas emails com currículo ou candidatura
const subject = email.subject || '';
const hasPdf = (email.attachments || []).some(a => a.contentType === 'application/pdf' || (a.filename || '').toLowerCase().endsWith('.pdf'));
const isCandidatura = /curriculo|curriculum|cv |vaga|candidatura|candidato|seleção/i.test(subject);

if (!hasPdf && !isCandidatura) {
  return []; // ignora email
}

const fromStr = email.from || '';
const emailMatch = fromStr.match(/[\w.-]+@[\w.-]+\.\w+/);
const nameMatch = fromStr.match(/^"?([^"<]+)"?\s*</);

const remetenteName = nameMatch?.[1]?.trim() || fromStr.split('@')[0];
const remetenteEmail = emailMatch?.[0] || '';

const bodyText = (email.textHtml?.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim() || email.text || '').substring(0, 3000);

const pdfAttachment = (email.attachments || []).find(a => a.contentType === 'application/pdf' || (a.filename || '').toLowerCase().endsWith('.pdf'));

return [{ json: { remetenteName, remetenteEmail, subject, bodyText, hasPdf: !!pdfAttachment, emailDate: email.date || new Date().toISOString() } }];

