parameters.jsCode:
const emailData = $('Extrair e Processar Email').first().json;
const claudeResp = $input.first().json;

const SUPABASE_URL = $vars.SUPABASE_URL;
const SUPABASE_KEY = $vars.SUPABASE_KEY;
const GOOGLE_KEY = $vars.GOOGLE_MAPS_API_KEY;
const ENDERECO_SEDE = $vars.ENDERECO_SEDE;
const RAIO_MAX = parseInt($vars.RAIO_MAXIMO_KM || '15');

// Parsear resposta Claude
let curriculo = {};
try {
  const text = claudeResp.content?.[0]?.text || '{}';
  curriculo = JSON.parse(text.replace(/```json\n?|```/g, '').trim());
} catch(e) {
  curriculo = { nome: emailData.remetenteName, email: emailData.remetenteEmail };
}

curriculo.nome = curriculo.nome || emailData.remetenteName;
curriculo.email = curriculo.email || emailData.remetenteEmail;
curriculo.cargo_desejado = curriculo.cargo_atual_desejado || emailData.subject;

// Geolocalização
let scoreGeo = 50, distKm = 0, durMin = 0, enderecoFormatado = '', lat = 0, lng = 0, dentroRaio = true;
const endereco = [curriculo.endereco_completo, curriculo.cidade, curriculo.estado, curriculo.cep].filter(Boolean).join(', ');

if (endereco && GOOGLE_KEY) {
  try {
    const geoResp = await fetch(`https://maps.googleapis.com/maps/api/geocode/json?address=${encodeURIComponent(endereco)}&key=${GOOGLE_KEY}&language=pt-BR&region=br`);
    const geoData = await geoResp.json();
    const geocode = geoData.results?.[0];
    lat = geocode?.geometry?.location?.lat || 0;
    lng = geocode?.geometry?.location?.lng || 0;
    enderecoFormatado = geocode?.formatted_address || endereco;

    const distResp = await fetch(`https://maps.googleapis.com/maps/api/distancematrix/json?origins=${encodeURIComponent(enderecoFormatado)}&destinations=${encodeURIComponent(ENDERECO_SEDE)}&key=${GOOGLE_KEY}&language=pt-BR&mode=driving`);
    const distData = await distResp.json();
    const el = distData.rows?.[0]?.elements?.[0];
    distKm = parseFloat(((el?.distance?.value || 999999) / 1000).toFixed(1));
    durMin = Math.round((el?.duration?.value || 0) / 60);
    dentroRaio = distKm <= RAIO_MAX;
    scoreGeo = distKm <= 8 ? 100 : distKm <= 10 ? 90 : distKm <= 12 ? 80 : distKm <= 13 ? 70 : distKm <= 14 ? 55 : distKm <= 15 ? 40 : 0;
  } catch(e) {}
}

// Score técnico
const anosExp = parseInt(curriculo.anos_experiencia || 0);
const formNivel = (curriculo.formacao_nivel || '').toLowerCase();
let scoreTec = 50 + (anosExp >= 3 ? 20 : anosExp >= 1 ? 10 : 0) + (formNivel.includes('superior') || formNivel.includes('mba') ? 20 : formNivel.includes('técnico') || formNivel.includes('tecnico') ? 10 : 0);
scoreTec = Math.min(100, scoreTec);
const scoreComp = 65;
const scoreFinal = Math.round(scoreTec * 0.5 + scoreGeo * 0.3 + scoreComp * 0.15);
const aprovado = scoreFinal >= 60 && dentroRaio;
const status = !dentroRaio ? 'fora_raio' : (aprovado ? 'qualificado' : 'banco_espera');

// Salvar no Supabase
const candidatoData = {
  nome: curriculo.nome,
  email: curriculo.email,
  telefone: curriculo.telefone || '',
  cpf_raw: curriculo.cpf || '',
  endereco_completo: enderecoFormatado || endereco,
  latitude: lat,
  longitude: lng,
  distancia_sede_km: distKm,
  cargo_desejado: curriculo.cargo_desejado,
  formacao: `${curriculo.formacao_nivel || ''} - ${curriculo.formacao_descricao || ''}`.trim(),
  anos_experiencia: anosExp,
  pretensao_salarial: curriculo.pretensao_salarial || '',
  disponibilidade_imediata: !!curriculo.disponibilidade_imediata,
  habilidades_array: curriculo.habilidades_array || [],
  idiomas_array: (curriculo.idiomas_array || []).map(i => typeof i === 'object' ? `${i.idioma} - ${i.nivel}` : i),
  certificacoes_array: curriculo.certificacoes_array || [],
  curriculo_texto_extraido: JSON.stringify(curriculo.experiencias || []),
  linkedin_url: curriculo.linkedin_url || '',
  score_medio: scoreFinal,
  status,
  fonte: 'email',
  updated_at: new Date().toISOString()
};

try {
  await fetch(`${SUPABASE_URL}/rest/v1/candidatos`, {
    method: 'POST',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'resolution=merge-duplicates,return=representation' },
    body: JSON.stringify(candidatoData)
  });
} catch(e) {}

// Analytics
try {
  await fetch(`${SUPABASE_URL}/rest/v1/analytics_triagem`, {
    method: 'POST',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ canal: 'email', candidato_email: curriculo.email, status_triagem: status, score_final: scoreFinal, dentro_raio: dentroRaio, created_at: new Date().toISOString() })
  });
} catch(e) {}

// Montar e-mail de retorno
const empresa = $vars.EMPRESA_NOME || 'nossa empresa';
const cargo = curriculo.cargo_desejado || 'a vaga';
let statusMsg;
if (!dentroRaio) {
  statusMsg = `⚠️ Seu endereço está a ${distKm} km do local (raio máximo: ${RAIO_MAX} km). Cadastro mantido para oportunidades na sua região.`;
} else {
  statusMsg = `✅ Aderência técnica: ${scoreFinal}/100. Localização validada: ${distKm} km do posto (${durMin} min). Caso seu perfil avance, contato via WhatsApp em até 48h.`;
}

return [{ json: { to: curriculo.email, nome: curriculo.nome, cargo, empresa, statusMsg, scoreFinal, distKm, dentroRaio } }];
